{
  "sentences": [
    {
      "text": "我沒有去過臺北的故宮。",
      "pinyin": "Wǒ méiyǒu qù guò Táiběi de Gùgōng.",
      "pinyin_numeric": "wo3 mei2you3 qu4 guo4 Tai2bei3 de0 Gu4gong1.",
      "translation_en": "I have never been to the National Palace Museum in Taipei.",
      "translation_ko": "저는 타이베이의 고궁에 가 본 적이 없습니다."
    },
    {
      "text": "你吃過臺南的牛肉麵嗎？",
      "pinyin": "Nǐ chī guò Táinán de niúròumiàn ma?",
      "pinyin_numeric": "ni3 chi1 guo4 Tai2nan2 de0 niu2rou4mian4 ma0?",
      "translation_en": "Have you ever eaten beef noodles in Tainan?",
      "translation_ko": "타이난의 소고기 국수를 먹어 본 적이 있나요?"
    },
    {
      "text": "我從來沒有喝過珍珠奶茶。",
      "pinyin": "Wǒ cónglái méiyǒu hē guò zhēnzhū nǎichá.",
      "pinyin_numeric": "wo3 cong2lai2 mei2you3 he1 guo4 zhen1zhu1 nai3cha2.",
      "translation_en": "I have never had bubble tea before.",
      "translation_ko": "저는 버블티를 마셔 본 적이 전혀 없습니다."
    },
    {
      "text": "他沒有看過這部電影。",
      "pinyin": "Tā méiyǒu kàn guò zhè bù diànyǐng.",
      "pinyin_numeric": "ta1 mei2you3 kan4 guo4 zhe4 bu4 dian4ying3.",
      "translation_en": "He has never seen this movie.",
      "translation_ko": "그는 이 영화를 본 적이 없습니다."
    },
    {
      "text": "我們沒有學過這個句子。",
      "pinyin": "Wǒmen méiyǒu xué guò zhège jùzi.",
      "pinyin_numeric": "wo3men0 mei2you3 xue2 guo4 zhe4ge0 ju4zi0.",
      "translation_en": "We have never studied this sentence before.",
      "translation_ko": "우리는 이 문장을 배운 적이 없습니다."
    },
    {
      "text": "你聽過這首歌嗎？我沒有聽過。",
      "pinyin": "Nǐ tīng guò zhè shǒu gē ma? Wǒ méiyǒu tīng guò.",
      "pinyin_numeric": "ni3 ting1 guo4 zhe4 shou3 ge1 ma0? wo3 mei2you3 ting1 guo4.",
      "translation_en": "Have you heard this song? I haven't heard it.",
      "translation_ko": "이 노래 들어 본 적 있나요? 저는 들어 본 적이 없습니다."
    },
    {
      "text": "她沒有去過國外旅行。",
      "pinyin": "Tā méiyǒu qù guò guówài lǚxíng.",
      "pinyin_numeric": "ta1 mei2you3 qu4 guo4 guo2wai4 lü3xing2.",
      "translation_en": "She has never traveled abroad.",
      "translation_ko": "그녀는 해외 여행을 가 본 적이 없습니다."
    },
    {
      "text": "我沒有吃過滷肉飯，但是我想試試看。",
      "pinyin": "Wǒ méiyǒu chī guò lǔròufàn, dànshì wǒ xiǎng shì shì kàn.",
      "pinyin_numeric": "wo3 mei2you3 chi1 guo4 lu3rou4fan4, dan4shi4 wo3 xiang3 shi4 shi4 kan4.",
      "translation_en": "I have never eaten braised pork rice, but I want to try it.",
      "translation_ko": "저는 루로우판을 먹어 본 적이 없지만, 한번 먹어 보고 싶습니다."
    },
    {
      "text": "你拍過臺中的風景照片嗎？",
      "pinyin": "Nǐ pāi guò Táizhōng de fēngjǐng zhàopiàn ma?",
      "pinyin_numeric": "ni3 pai1 guo4 Tai2zhong1 de0 feng1jing3 zhao4pian4 ma0?",
      "translation_en": "Have you ever taken photos of the scenery in Taichung?",
      "translation_ko": "타이중의 풍경 사진을 찍어 본 적이 있나요?"
    },
    {
      "text": "我從來沒有做過這個工作。",
      "pinyin": "Wǒ cónglái méiyǒu zuò guò zhège gōngzuò.",
      "pinyin_numeric": "wo3 cong2lai2 mei2you3 zuo4 guo4 zhe4ge0 gong1zuo4.",
      "translation_en": "I have never done this job before.",
      "translation_ko": "저는 이 일을 해 본 적이 전혀 없습니다."
    }
  ]
}
